import type { CareerQuestion } from "./rrt-questions";

export const cardiacSonographerQuestionsBatch8: CareerQuestion[] = [
  { id: "cardecho-570", stem: "Cardiac output (CO) by echocardiography is most commonly calculated using which method?", options: ["Doppler-derived stroke volume (LVOT VTI × LVOT area) multiplied by heart rate", "Simpson biplane method alone", "M-mode fractional shortening multiplied by heart rate", "Visual estimation of ejection fraction"], correctIndex: 0, rationale: "CO = SV × HR. Stroke volume is calculated as LVOT cross-sectional area (π × (D/2)²) × LVOT VTI from PW Doppler. This volumetric flow method is the standard echocardiographic technique for CO determination.", difficulty: 1, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-571", stem: "The LVOT diameter for cardiac output calculation is measured in which view and at what location?", options: ["Parasternal long-axis view, inner edge to inner edge at the aortic annulus in mid-systole", "Apical four-chamber view at the mitral annulus", "Parasternal short-axis at the papillary muscle level", "Subcostal view at the IVC-RA junction"], correctIndex: 0, rationale: "LVOT diameter is measured in the PLAX view at the aortic annulus (hinge points of the aortic valve cusps) during mid-systole, using inner-edge to inner-edge convention. This measurement is critical because it is squared in the area calculation, amplifying errors.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-572", stem: "A 1 mm error in LVOT diameter measurement will result in approximately what percentage error in stroke volume?", options: ["Up to 10-15% because the diameter is squared in the area calculation", "Less than 1%", "Exactly 5%", "No significant effect"], correctIndex: 0, rationale: "Since CSA = π(D/2)², the diameter is squared, amplifying measurement errors. For example, measuring 2.0 cm vs 2.1 cm yields areas of 3.14 vs 3.46 cm², a 10% difference. This is the most common source of error in Doppler CO calculation.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-573", stem: "LVOT VTI is obtained using which Doppler modality and from which window?", options: ["Pulsed-wave Doppler from the apical five-chamber or apical long-axis view with the sample volume at the LVOT", "Continuous-wave Doppler from the parasternal window", "Color M-mode from the subcostal view", "Tissue Doppler from the apical four-chamber view"], correctIndex: 0, rationale: "PW Doppler is used because it provides site-specific velocity measurement at the LVOT (sample volume placed just proximal to the aortic valve). CW Doppler would record the highest velocity along the beam, typically the aortic valve jet, not LVOT flow.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-574", stem: "Normal cardiac output at rest in an average adult is approximately:", options: ["4-8 L/min", "1-2 L/min", "10-15 L/min", "20-25 L/min"], correctIndex: 0, rationale: "Normal resting CO is 4-8 L/min. Cardiac index (CI = CO/BSA) normalizes for body size; normal CI is 2.5-4.0 L/min/m². CI < 2.2 L/min/m² indicates reduced cardiac output.", difficulty: 1, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-575", stem: "Cardiac index is calculated by dividing cardiac output by:", options: ["Body surface area (BSA)", "Body weight", "Height", "Age"], correctIndex: 0, rationale: "Cardiac index (CI) = CO / BSA. BSA is calculated using height and weight (DuBois formula). CI normalizes CO for body size, allowing meaningful comparison between patients. Normal CI = 2.5-4.0 L/min/m².", difficulty: 1, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-576", stem: "The thermodilution method of measuring cardiac output is performed using:", options: ["A pulmonary artery (Swan-Ganz) catheter with injection of cold saline and measurement of temperature change", "Echocardiographic Doppler at the mitral valve", "Peripheral arterial catheter", "Central venous pressure monitoring alone"], correctIndex: 0, rationale: "Thermodilution is the invasive gold standard for CO measurement. Cold saline is injected into the RA port, and the temperature change at the PA thermistor is measured. The area under the thermodilution curve is inversely proportional to CO (Stewart-Hamilton equation).", difficulty: 2, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-577", stem: "Doppler cardiac output measurement at the mitral valve uses which parameters?", options: ["Mitral annular area × mitral inflow VTI", "LVOT diameter × aortic VTI", "Pulmonary vein velocity × LA area", "Tricuspid annular velocity × RA area"], correctIndex: 0, rationale: "CO can be calculated at the mitral annulus: SV = mitral annular area × mitral VTI. However, the LVOT method is preferred because the LVOT is more circular and has less variation in size during the cardiac cycle than the mitral annulus.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-578", stem: "In the Fick method, cardiac output is calculated using:", options: ["Oxygen consumption divided by the arteriovenous oxygen content difference", "Heart rate times stroke volume from VTI", "Mean arterial pressure divided by systemic vascular resistance", "Ejection fraction times end-diastolic volume"], correctIndex: 0, rationale: "Fick principle: CO = VO₂ / (CaO₂ - CvO₂). VO₂ is oxygen consumption (measured or estimated), CaO₂ is arterial O₂ content, CvO₂ is mixed venous O₂ content. This is considered the reference standard for CO measurement.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-579", stem: "Stroke volume measured by Doppler at the LVOT should be compared with which other measurement to check for valvular regurgitation?", options: ["Stroke volume measured at the mitral annulus; a significant difference suggests valvular regurgitation", "Aortic root diameter", "Left atrial volume", "RV systolic pressure"], correctIndex: 0, rationale: "In the absence of regurgitation, SV at the LVOT should equal SV at the mitral annulus. If LVOT SV exceeds mitral SV, aortic regurgitation is present. If mitral SV exceeds LVOT SV, mitral regurgitation is present. The difference equals the regurgitant volume.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-580", stem: "Right atrial pressure (RAP) is estimated echocardiographically by assessing:", options: ["IVC diameter and its respiratory variation (collapse index)", "Tricuspid valve E/A ratio", "Pulmonary artery acceleration time", "Mitral annular e' velocity"], correctIndex: 0, rationale: "IVC diameter ≤2.1 cm with >50% inspiratory collapse estimates RAP ~3 mmHg. IVC >2.1 cm with <50% collapse estimates RAP ~15 mmHg. Intermediate findings estimate RAP ~8 mmHg. This is essential for calculating RVSP from TR velocity.", difficulty: 1, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-581", stem: "Right ventricular systolic pressure (RVSP) is estimated using:", options: ["Peak tricuspid regurgitation velocity squared times 4 plus estimated RAP (simplified Bernoulli equation)", "Mitral inflow E velocity", "LVOT VTI", "Aortic valve mean gradient"], correctIndex: 0, rationale: "RVSP = 4(TR Vmax)² + RAP. In the absence of pulmonic stenosis, RVSP equals pulmonary artery systolic pressure (PASP). A TR velocity >2.8 m/s (RVSP >36 mmHg assuming RAP 3) suggests elevated PA pressure.", difficulty: 1, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-582", stem: "Pulmonary artery diastolic pressure can be estimated from:", options: ["End-diastolic pulmonary regurgitation velocity using 4V² + RAP", "Peak TR velocity", "Mitral E/A ratio", "Aortic valve peak gradient"], correctIndex: 0, rationale: "PA diastolic pressure = 4(PR end-diastolic velocity)² + RAP. This supplements PASP estimation and helps calculate mean PA pressure. Mean PAP can be estimated as 0.61 × PASP + 2 mmHg or from early PR velocity: 4(PR peak velocity)² + RAP.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-583", stem: "Mean pulmonary artery pressure (mPAP) can be estimated echocardiographically by:", options: ["Using the early peak PR velocity: mPAP = 4(early PR velocity)² + RAP", "Using the aortic valve peak velocity", "Measuring the LA diameter", "Using the mitral A wave duration"], correctIndex: 0, rationale: "The early peak velocity of pulmonary regurgitation reflects the pressure gradient between the PA and RV at the onset of diastole. Adding RAP gives an estimate of mPAP. Normal mPAP is <20 mmHg; ≥25 mmHg defines pulmonary hypertension.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-584", stem: "Left atrial pressure (LAP) can be estimated using the E/e' ratio. An E/e' ratio >14 suggests:", options: ["Elevated LV filling pressure (PCWP >15 mmHg)", "Normal LV filling pressure", "Pulmonary hypertension without left heart disease", "Aortic stenosis"], correctIndex: 0, rationale: "E/e' is the ratio of mitral E velocity to the average of septal and lateral mitral annular e' velocities. E/e' >14 estimates elevated LAP/PCWP. E/e' <8 suggests normal filling pressure. Values 8-14 are indeterminate and require additional parameters.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-585", stem: "LV end-diastolic pressure (LVEDP) can be estimated by comparing:", options: ["The duration of the mitral A wave to the pulmonary vein Ar wave; Ar-A duration >30 ms suggests elevated LVEDP", "TR velocity to PR velocity", "LVOT VTI to aortic VTI", "E/A ratio alone"], correctIndex: 0, rationale: "The pulmonary vein Ar wave reflects LA contraction against the pulmonary veins. When LVEDP is elevated, the mitral A wave is shortened and the Ar wave is prolonged. Ar duration minus A duration >30 ms indicates elevated LVEDP with high specificity.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-586", stem: "In a patient with atrial fibrillation, which parameter is MOST useful for estimating LV filling pressure?", options: ["E/e' ratio (septal and lateral average)", "E/A ratio", "Pulmonary vein Ar wave duration", "Isovolumic relaxation time"], correctIndex: 0, rationale: "In atrial fibrillation, the A wave is absent, so E/A ratio and Ar wave duration cannot be used. E/e' ratio remains valid and is the primary parameter for estimating filling pressures in AF. An E/e' >14 suggests elevated filling pressures.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-587", stem: "The LV dP/dt is a measure of:", options: ["LV contractility, specifically the rate of pressure rise during isovolumic contraction", "LV relaxation rate", "Aortic valve gradient", "Pulmonary artery pressure"], correctIndex: 0, rationale: "dP/dt (rate of pressure change over time) reflects LV systolic performance. It is measured from the MR CW Doppler signal: the time interval between 1 m/s and 3 m/s on the MR jet corresponds to a pressure change of 32 mmHg (4×9 - 4×1 = 32 mmHg).", difficulty: 3, category: "Advanced Hemodynamics", topic: "dP/dt" },
  { id: "cardecho-588", stem: "To measure dP/dt from the MR jet, the time interval is measured between which two velocity points?", options: ["1 m/s and 3 m/s on the ascending limb of the MR CW Doppler signal", "0 m/s and peak velocity", "Peak velocity and return to baseline", "2 m/s and 4 m/s"], correctIndex: 0, rationale: "dP/dt = 32 mmHg / Δt (seconds). The 32 mmHg is derived from the simplified Bernoulli equation: P at 3 m/s = 4(9) = 36 mmHg, P at 1 m/s = 4(1) = 4 mmHg; 36-4 = 32 mmHg. Normal dP/dt is >1200 mmHg/s; <800 mmHg/s indicates severe LV dysfunction.", difficulty: 4, category: "Advanced Hemodynamics", topic: "dP/dt" },
  { id: "cardecho-589", stem: "A dP/dt value of <800 mmHg/s suggests:", options: ["Severely impaired LV systolic function", "Normal LV contractility", "Aortic stenosis", "Pericardial constriction"], correctIndex: 0, rationale: "Normal LV dP/dt is >1200 mmHg/s. Values <1000 mmHg/s indicate impaired contractility, and <800 mmHg/s indicates severe systolic dysfunction. dP/dt is relatively preload-independent but requires a measurable MR jet for calculation.", difficulty: 2, category: "Advanced Hemodynamics", topic: "dP/dt" },
  { id: "cardecho-590", stem: "A limitation of using dP/dt as an index of LV contractility is:", options: ["It requires the presence of at least mild mitral regurgitation to be measurable", "It is too sensitive to afterload changes", "It requires TEE for accurate measurement", "It can only be measured during stress testing"], correctIndex: 0, rationale: "dP/dt measurement requires an MR CW Doppler signal with a clearly defined ascending limb. Without MR, this measurement cannot be obtained. Additionally, dP/dt may be affected by LA pressure changes in severe MR.", difficulty: 3, category: "Advanced Hemodynamics", topic: "dP/dt" },
  { id: "cardecho-591", stem: "The Tei index (myocardial performance index, MPI) measures:", options: ["Combined systolic and diastolic function as the ratio of isovolumic time intervals to ejection time", "Only systolic function", "Only diastolic function", "Valve area"], correctIndex: 0, rationale: "Tei index = (ICT + IRT) / ET, where ICT = isovolumic contraction time, IRT = isovolumic relaxation time, ET = ejection time. It can also be calculated as (MCOT - ET) / ET. Normal LV Tei index is <0.40 by PW Doppler.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Tei Index" },
  { id: "cardecho-592", stem: "To calculate the Tei index using PW Doppler, which two measurements are needed?", options: ["Mitral valve closure-to-opening time (MCOT) and LV ejection time (ET) from the LVOT", "Peak E velocity and peak A velocity", "TR velocity and PR velocity", "LVOT VTI and aortic valve VTI"], correctIndex: 0, rationale: "Tei index = (MCOT - ET) / ET. MCOT is measured from the end of the mitral A wave to the beginning of the next mitral E wave (includes ICT + ET + IRT). ET is measured from the LVOT Doppler envelope. Two separate cardiac cycles are needed.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Tei Index" },
  { id: "cardecho-593", stem: "The Tei index can also be measured using tissue Doppler imaging (TDI). What is the advantage of TDI-derived Tei index?", options: ["It can be measured from a single cardiac cycle using the mitral annular velocity pattern", "It is more accurate than PW Doppler", "It does not require an apical view", "It can measure valve areas"], correctIndex: 0, rationale: "TDI at the mitral annulus shows the s', e', and a' waves with the isovolumic intervals in a single tracing, eliminating beat-to-beat variability that occurs with the two-cycle PW Doppler method. Normal TDI-derived Tei index is <0.55.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Tei Index" },
  { id: "cardecho-594", stem: "An elevated Tei index (>0.40 by PW Doppler) indicates:", options: ["Global myocardial dysfunction (both systolic and diastolic impairment)", "Isolated diastolic dysfunction", "Normal ventricular function", "Valvular stenosis only"], correctIndex: 0, rationale: "The Tei index increases with prolonged isovolumic intervals (impaired contractility and relaxation) and shortened ejection time (reduced SV). It reflects combined systolic and diastolic dysfunction and is prognostically significant in heart failure and amyloidosis.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Tei Index" },
  { id: "cardecho-595", stem: "The RV Tei index is particularly useful in evaluating:", options: ["Right ventricular function in pulmonary hypertension and congenital heart disease", "Aortic valve stenosis severity", "Mitral valve prolapse", "Left atrial size"], correctIndex: 0, rationale: "The RV Tei index assesses global RV function, which is difficult to measure by other methods due to the RV's complex geometry. Normal RV Tei index is <0.40 (PW) or <0.55 (TDI). It is elevated in pulmonary hypertension, RV infarction, and Ebstein anomaly.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Tei Index" },
  { id: "cardecho-596", stem: "Qp/Qs ratio is used to quantify:", options: ["The magnitude of intracardiac shunting by comparing pulmonary to systemic blood flow", "Valvular regurgitation severity", "Diastolic function grade", "Coronary artery flow reserve"], correctIndex: 0, rationale: "Qp/Qs = pulmonary blood flow / systemic blood flow. A Qp/Qs of 1.0 is normal (no shunt). Qp/Qs >1.5 indicates a hemodynamically significant left-to-right shunt. Qp/Qs <1.0 indicates right-to-left shunting.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-597", stem: "Echocardiographic Qp/Qs is calculated by measuring stroke volumes at:", options: ["The RVOT (Qp) and LVOT (Qs), using their respective diameters and VTIs", "The mitral and tricuspid valves only", "The aortic and pulmonary valve peak velocities only", "The IVC and SVC diameters"], correctIndex: 0, rationale: "Qp = RVOT area × RVOT VTI; Qs = LVOT area × LVOT VTI. In a left-to-right shunt (e.g., ASD), Qp > Qs. The RVOT diameter is measured in the PSAX view at the pulmonic valve level. Accurate diameter measurement is critical.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-598", stem: "A Qp/Qs ratio of 2.0 in a patient with an ASD means:", options: ["Pulmonary blood flow is twice the systemic blood flow, indicating a significant left-to-right shunt", "Systemic blood flow is twice the pulmonary flow", "There is no significant shunt", "Right-to-left shunting is present"], correctIndex: 0, rationale: "Qp/Qs = 2.0 means twice as much blood flows through the pulmonary circuit compared to the systemic circuit. This indicates a hemodynamically significant shunt that generally warrants closure to prevent RV volume overload and pulmonary hypertension.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-599", stem: "In a patient with a VSD, the shunt direction and velocity can be assessed by:", options: ["Color flow Doppler showing the jet direction and CW Doppler measuring the peak velocity across the defect", "M-mode at the IVS", "Tissue Doppler at the septal annulus", "Strain imaging of the septum"], correctIndex: 0, rationale: "Color Doppler shows the shunt jet direction (left-to-right appears as a systolic jet from LV to RV). CW Doppler across the VSD measures the pressure gradient: ΔP = 4V². High velocity (>4 m/s) suggests a restrictive VSD with large LV-RV pressure gradient.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-600", stem: "The interventricular pressure gradient across a VSD can be used to estimate RV systolic pressure by:", options: ["Subtracting the VSD gradient from systolic blood pressure: RVSP = SBP - 4(VSD velocity)²", "Adding the VSD gradient to the systolic blood pressure", "Multiplying the VSD velocity by heart rate", "Dividing systolic pressure by the VSD gradient"], correctIndex: 0, rationale: "In a left-to-right VSD, the pressure gradient = LV systolic pressure - RV systolic pressure. Since LV systolic pressure approximates SBP (without aortic stenosis): RVSP = SBP - 4V². A low VSD velocity suggests near-systemic RV pressure (Eisenmenger risk).", difficulty: 4, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-601", stem: "Pulmonary vascular resistance (PVR) can be estimated echocardiographically using:", options: ["TR velocity divided by RVOT VTI (PVR ≈ TRV/RVOT VTI × 10 + 0.16 Wood units)", "Aortic valve area", "Mitral E/A ratio", "LV mass index"], correctIndex: 0, rationale: "Abbas formula: PVR (Wood units) ≈ TRV(m/s) / RVOT VTI(cm) × 10 + 0.16. This correlates well with invasive PVR. TRV/RVOT VTI >0.2 suggests elevated PVR. Normal PVR is <3 Wood units. This estimate guides management of pulmonary hypertension.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-602", stem: "Systemic vascular resistance (SVR) can be estimated by:", options: ["80 × (MAP - CVP) / CO, using echocardiographic CO measurement", "Aortic peak velocity × LVOT area", "E/e' × heart rate", "Mitral valve area × gradient"], correctIndex: 0, rationale: "SVR = 80 × (MAP - CVP) / CO. While MAP and CVP require clinical measurement, CO can be provided by echocardiographic Doppler. Normal SVR is 800-1200 dynes·s/cm⁵ (10-15 Wood units). Elevated SVR is seen in heart failure and hypertension.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-603", stem: "The pulmonary artery acceleration time (PAAT) is measured from:", options: ["The onset to peak of the RVOT PW Doppler flow signal", "The onset to end of the LVOT signal", "The beginning to end of the TR jet", "The E wave onset to peak"], correctIndex: 0, rationale: "PAAT is the time from the beginning of RVOT flow to peak velocity. Normal PAAT >130 ms. PAAT <105 ms suggests significant pulmonary hypertension (mPAP >25 mmHg). Mid-systolic notching of the RVOT signal also indicates elevated PVR.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-604", stem: "A mid-systolic notch on the RVOT Doppler signal is characteristic of:", options: ["Elevated pulmonary vascular resistance with reflected pressure waves from the pulmonary vasculature", "Normal pulmonary hemodynamics", "Pulmonic stenosis", "Tricuspid regurgitation"], correctIndex: 0, rationale: "The mid-systolic notch (or deceleration) on the RVOT Doppler envelope results from early reflected pressure waves from the stiff, high-resistance pulmonary vasculature. It is highly specific for pre-capillary pulmonary hypertension with elevated PVR.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-605", stem: "Valve resistance is calculated as:", options: ["Mean pressure gradient divided by flow rate across the valve (ΔP/Q)", "Peak velocity times valve area", "VTI times heart rate", "Annular diameter squared times π"], correctIndex: 0, rationale: "Valve resistance = ΔP(mean) / Q, where Q is the flow rate (SV/SEP). Unlike valve area, resistance accounts for both pressure gradient and flow. It may better reflect stenosis severity in low-flow states because it is less flow-dependent than gradient alone.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-606", stem: "In low-flow, low-gradient aortic stenosis, valve resistance may be more helpful than valve area because:", options: ["Valve resistance is less affected by flow rate and better discriminates true severe stenosis from pseudo-severe stenosis", "Valve resistance is easier to measure", "Valve resistance does not require Doppler", "Valve area is always accurate regardless of flow"], correctIndex: 0, rationale: "In low-flow states, the valve may not fully open, giving a small calculated area (pseudo-severe AS). True severe AS has high resistance (>300 dynes·s/cm⁵) regardless of flow. Pseudo-severe AS has lower resistance that decreases with increased flow during dobutamine stress.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-607", stem: "The continuity equation for aortic valve area calculation assumes:", options: ["Flow volume proximal to the valve (LVOT) equals flow volume through the valve (conservation of mass)", "Valve area remains constant throughout systole", "LVOT velocity equals aortic velocity", "Pressure proximal and distal to the valve are equal"], correctIndex: 0, rationale: "The continuity equation states that volume flow is constant: A1 × V1 = A2 × V2. Therefore, AVA = (LVOT area × LVOT VTI) / AV VTI. This assumes a circular LVOT cross-section and that all flow passes through the stenotic orifice.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-608", stem: "The dimensionless velocity index (DVI) for aortic stenosis is:", options: ["LVOT VTI divided by AV VTI (or LVOT peak velocity / AV peak velocity)", "AV peak velocity × LVOT area", "AV mean gradient / heart rate", "LVOT diameter / aortic root diameter"], correctIndex: 0, rationale: "DVI = LVOT VTI / AV VTI. Normal DVI ≥0.50. DVI <0.25 indicates severe AS. DVI eliminates the LVOT diameter measurement, removing the most error-prone variable. It is especially useful when LVOT diameter measurement is difficult.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-609", stem: "The Gorlin formula, used in the cardiac catheterization lab, relates valve area to:", options: ["Flow rate and the square root of the mean pressure gradient across the valve", "Peak velocity and valve annulus diameter", "Heart rate and stroke volume only", "Systolic blood pressure and cardiac output"], correctIndex: 0, rationale: "Gorlin formula: AVA = CO / (SEP × HR × 44.3 × √ΔP). SEP is systolic ejection period. The constant 44.3 is an empirical correction factor. It was the standard before Doppler echo and remains the invasive reference for valve area calculation.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-610", stem: "The Hakki simplified formula for aortic valve area uses:", options: ["CO divided by the square root of the peak-to-peak aortic gradient", "Mean gradient multiplied by LVOT area", "Peak velocity times ejection time", "Stroke volume divided by heart rate"], correctIndex: 0, rationale: "Hakki formula: AVA = CO / √(peak-to-peak gradient). This simplified version of the Gorlin formula is accurate at heart rates of 60-100 bpm. It was widely used in the cath lab before widespread Doppler echocardiographic valve area measurement.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-611", stem: "Transmitral pressure gradient in mitral stenosis is best measured using:", options: ["CW Doppler across the mitral valve from the apical window, tracing the diastolic envelope for mean gradient", "PW Doppler at the LVOT", "Color Doppler M-mode", "2D planimetry alone"], correctIndex: 0, rationale: "CW Doppler measures the peak and mean gradients across the stenotic mitral valve. Mean gradient is obtained by tracing the diastolic Doppler envelope. Mean gradient >10 mmHg indicates severe MS. Gradients are heart rate dependent.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-612", stem: "The pressure half-time (PHT) method for mitral valve area calculates:", options: ["MVA = 220 / PHT (ms), where PHT is the time for the peak gradient to decrease by half", "MVA = PHT × 220", "MVA = E velocity / PHT", "MVA = DT / 220"], correctIndex: 0, rationale: "PHT is the time for the peak pressure gradient to decrease to half its value. MVA = 220/PHT. PHT >220 ms corresponds to MVA <1.0 cm² (severe MS). The method may be inaccurate with significant AR, abnormal LV compliance, or immediately after valvuloplasty.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-613", stem: "The proximal isovelocity surface area (PISA) method quantifies:", options: ["Regurgitant flow by measuring the convergence zone proximal to the regurgitant orifice", "Stenotic valve area by measuring the distal jet", "Cardiac output at the LVOT", "LV filling pressure from E/e'"], correctIndex: 0, rationale: "PISA uses the flow convergence zone on the ventricular (for MR) or atrial (for AR) side of the regurgitant orifice. EROA = (2πr² × aliasing velocity) / peak regurgitant velocity. It provides EROA, regurgitant volume, and regurgitant fraction.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-614", stem: "For PISA measurement of mitral regurgitation, the aliasing velocity is typically set to:", options: ["30-40 cm/s to create a well-defined hemispheric convergence zone", "100-150 cm/s", "200 cm/s", "5 cm/s"], correctIndex: 0, rationale: "The aliasing velocity is shifted (baseline moved) to approximately 30-40 cm/s to create a measurable hemisphere on the ventricular side of the MR orifice. The PISA radius is measured from the orifice to the aliasing boundary at this velocity.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-615", stem: "Using PISA, an EROA ≥0.40 cm² for mitral regurgitation indicates:", options: ["Severe primary (degenerative) mitral regurgitation", "Mild MR", "Moderate MR", "Trace MR"], correctIndex: 0, rationale: "ASE criteria for severe primary MR: EROA ≥0.40 cm², regurgitant volume ≥60 mL, regurgitant fraction ≥50%. For secondary (functional) MR, the threshold is lower: EROA ≥0.20 cm² is considered severe due to its association with poor outcomes.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-616", stem: "The vena contracta width in mitral regurgitation represents:", options: ["The narrowest portion of the regurgitant jet as it passes through the regurgitant orifice", "The widest portion of the regurgitant jet in the left atrium", "The LVOT diameter", "The mitral annular diameter"], correctIndex: 0, rationale: "The vena contracta is the narrowest cross-section of the MR jet, measured just downstream of the flow convergence zone. VC width ≥7 mm indicates severe MR. It is relatively independent of hemodynamic conditions and machine settings.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-617", stem: "3D vena contracta area (VCA) for mitral regurgitation provides what advantage over 2D vena contracta width?", options: ["It accounts for the non-circular shape of the regurgitant orifice, providing a more accurate EROA estimate", "It is faster to measure", "It requires less expertise", "It is only useful for aortic regurgitation"], correctIndex: 0, rationale: "The MR orifice is often elliptical or crescentic, especially in functional MR. 2D VC width assumes a circular orifice and may under- or overestimate severity. 3D VCA directly measures the non-circular orifice area, correlating better with angiographic MR severity.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-618", stem: "Regurgitant volume by the volumetric method for MR is calculated as:", options: ["Total mitral SV (mitral annular area × mitral VTI) minus forward SV (LVOT area × LVOT VTI)", "Peak MR velocity × MR jet area", "E velocity × deceleration time", "Aortic VTI × mitral VTI"], correctIndex: 0, rationale: "Regurgitant volume = total SV - forward SV. Total SV is measured at the mitral annulus (where all blood enters the LV). Forward SV is measured at the LVOT (blood leaving to the aorta). The difference is the blood regurgitated back into the LA.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-619", stem: "Regurgitant fraction is calculated as:", options: ["Regurgitant volume divided by total stroke volume times 100%", "Regurgitant volume × heart rate", "Forward SV / total SV", "Peak velocity / mean velocity"], correctIndex: 0, rationale: "RF = (RVol / Total SV) × 100%. RF <30% = mild, 30-49% = moderate, ≥50% = severe regurgitation. This metric helps integrate the volume of regurgitant flow relative to total LV output to grade severity.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-620", stem: "In the presence of both MR and AR, the volumetric method for quantifying one regurgitant lesion requires:", options: ["Using a competent valve as the reference for forward stroke volume", "Adding both regurgitant volumes together", "Only visual jet assessment", "Ignoring the second lesion"], correctIndex: 0, rationale: "With combined MR and AR, neither the mitral nor LVOT SV represents pure forward flow. The pulmonic valve (if competent) can serve as the reference for systemic forward SV. Regurgitant volumes are then calculated by subtraction from the respective valve's total SV.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-621", stem: "The isovolumic relaxation time (IVRT) is measured from:", options: ["Aortic valve closure to mitral valve opening", "Mitral valve closure to aortic valve opening", "Peak E velocity to peak A velocity", "End of the S wave to onset of the D wave"], correctIndex: 0, rationale: "IVRT is the interval between aortic valve closure (end of systole) and mitral valve opening (beginning of filling). It is measured using CW Doppler between the aortic outflow and mitral inflow signals, or from tissue Doppler. Normal IVRT is 70-90 ms.", difficulty: 1, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-622", stem: "A shortened IVRT (<60 ms) is seen in:", options: ["Elevated left atrial pressure or constrictive pericarditis causing early mitral valve opening", "Normal diastolic function in a young patient", "Severe aortic stenosis", "Hypertrophic cardiomyopathy with preserved diastolic function"], correctIndex: 0, rationale: "Elevated LAP causes the mitral valve to open earlier because the LV pressure falls to the (elevated) LA pressure sooner. IVRT <60 ms combined with elevated E/A ratio and short DT suggests restrictive filling (Grade III diastolic dysfunction).", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-623", stem: "The deceleration time (DT) of the mitral E wave in restrictive filling is typically:", options: ["<160 ms due to rapid pressure equalization between the LA and LV", "300-400 ms", ">500 ms", "Not measurable"], correctIndex: 0, rationale: "In restrictive filling (Grade III), the elevated LAP drives rapid early filling that decelerates quickly as the stiff, non-compliant LV pressure rises rapidly. DT <160 ms indicates restrictive physiology and is associated with poor prognosis in heart failure.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-624", stem: "Pulmonary venous flow in the normal pattern shows:", options: ["Systolic dominant flow (S > D) with a small atrial reversal (Ar) wave", "Diastolic dominant flow with large Ar wave", "Equal S and D waves with no Ar wave", "Reversed systolic flow"], correctIndex: 0, rationale: "Normal pulmonary venous flow: S wave (systolic forward flow) > D wave (diastolic forward flow), with a small Ar wave (<35 cm/s, duration < mitral A duration). With elevated LAP, the pattern shifts to diastolic dominance (D > S).", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-625", stem: "Systolic blunting or reversal of pulmonary venous flow is seen in:", options: ["Severe mitral regurgitation or markedly elevated left atrial pressure", "Normal diastolic function", "Pulmonary stenosis", "Aortic stenosis"], correctIndex: 0, rationale: "In severe MR, the regurgitant jet increases LA systolic pressure, reducing or reversing the systolic component of pulmonary venous flow. Systolic flow reversal is a specific sign of severe MR and elevated LAP.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-626", stem: "The hepatic vein flow pattern in severe tricuspid regurgitation shows:", options: ["Systolic flow reversal reflecting elevated RA pressure during ventricular systole", "Normal antegrade systolic flow", "Continuous antegrade flow", "Only diastolic flow reversal"], correctIndex: 0, rationale: "Normal hepatic vein flow is antegrade in systole and diastole with brief reversals during atrial contraction (Ar) and late systole (V). In severe TR, the regurgitant jet raises RA pressure during systole, reversing hepatic vein systolic flow.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-627", stem: "The E/A ratio of mitral inflow in Grade I diastolic dysfunction (impaired relaxation) is:", options: ["<0.8 with prolonged DT (>200 ms) and prolonged IVRT (>100 ms)", ">2.0 with DT <160 ms", "1.0-1.5 with normal DT", "Variable with no consistent pattern"], correctIndex: 0, rationale: "Grade I (impaired relaxation): E/A <0.8, DT >200 ms, IVRT >100 ms, e' reduced. This is the earliest stage of diastolic dysfunction, seen with normal LAP. It is common in elderly and hypertensive patients.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-628", stem: "Pseudonormal filling (Grade II diastolic dysfunction) can be differentiated from normal by:", options: ["Tissue Doppler showing reduced e' velocity and elevated E/e' ratio despite a normal-appearing E/A ratio", "2D imaging alone", "M-mode of the mitral valve", "Color Doppler of the aortic valve"], correctIndex: 0, rationale: "Pseudonormal has E/A 0.8-2.0 resembling normal. However, TDI shows reduced e' (<7 cm/s septal, <10 cm/s lateral), elevated E/e' (>14), and the Valsalva maneuver may unmask an impaired relaxation pattern (E/A reversal).", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-629", stem: "Which parameter best distinguishes constrictive pericarditis from restrictive cardiomyopathy?", options: ["Mitral annular e' velocity: normal or elevated in constriction, reduced in restriction", "LVEF", "LV mass", "Aortic valve gradient"], correctIndex: 0, rationale: "In constriction, the myocardium is intrinsically normal, so e' is preserved (annulus paradoxus: e' ≥8 cm/s despite elevated filling pressures). In restriction, myocardial disease reduces e'. This differentiation is one of the most clinically important applications of TDI.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-630", stem: "Respiratory variation of mitral and tricuspid inflow velocities is exaggerated in:", options: ["Constrictive pericarditis (>25% mitral E velocity variation with respiration)", "Restrictive cardiomyopathy", "Normal hearts", "Dilated cardiomyopathy"], correctIndex: 0, rationale: "In constrictive pericarditis, the rigid pericardium enhances ventricular interdependence. Inspiration increases tricuspid inflow but decreases mitral inflow (and vice versa). >25% respiratory variation in mitral E velocity is characteristic of constriction.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-631", stem: "The stroke work index is calculated as:", options: ["SVI × (MAP - PCWP) × 0.0136", "CO × SVR", "SV × heart rate", "EF × EDV"], correctIndex: 0, rationale: "Stroke work index = SVI × (MAP - PCWP) × 0.0136 (g·m/m²). It represents the work done by the LV per beat per unit BSA. Normal LVSWI = 50-62 g·m/m². Reduced LVSWI indicates impaired LV performance and is prognostic in cardiogenic shock.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-632", stem: "In the assessment of aortic regurgitation severity, the pressure half-time of the AR jet is measured by:", options: ["CW Doppler of the AR diastolic signal; PHT <200 ms indicates severe AR with rapid equalization of aortic and LV pressures", "PW Doppler at the LVOT", "Color Doppler jet width", "M-mode of the aortic valve"], correctIndex: 0, rationale: "The AR PHT reflects the rate of diastolic pressure equalization between the aorta and LV. PHT <200 ms = severe AR (rapid filling raises LVEDP quickly). PHT >500 ms = mild AR. This is particularly useful when other methods are difficult.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-633", stem: "Holodiastolic flow reversal in the descending thoracic or abdominal aorta indicates:", options: ["At least moderate-to-severe aortic regurgitation", "Normal aortic valve function", "Aortic stenosis", "Mitral regurgitation"], correctIndex: 0, rationale: "Holodiastolic flow reversal in the descending aorta (by PW Doppler in the suprasternal or subcostal views) indicates significant AR. Brief early diastolic reversal may be normal, but holodiastolic reversal is specific for at least moderate-to-severe AR.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-634", stem: "The LV power output can be estimated as:", options: ["Cardiac output × mean arterial pressure", "Stroke volume × ejection time", "Heart rate × blood pressure", "E/e' × LVOT VTI"], correctIndex: 0, rationale: "LV power = CO × MAP (in watts when using proper unit conversion). Cardiac power output (CPO = CO × MAP / 451) measured in watts is a strong independent predictor of mortality in cardiogenic shock. Normal CPO is approximately 1 watt.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-635", stem: "Doppler-derived pulmonary venous systolic to diastolic (S/D) ratio assessment helps evaluate:", options: ["Left atrial pressure and diastolic function", "Right ventricular systolic pressure", "Aortic valve area", "LVOT obstruction"], correctIndex: 0, rationale: "Normal S/D ratio >1 (systolic dominance). With elevated LAP, the S wave decreases and D wave increases (S/D <1). Systolic blunting (S/D <1) combined with elevated E/e' helps confirm elevated filling pressures in indeterminate diastolic function cases.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-636", stem: "The Tei index is considered advantageous over LVEF because:", options: ["It is independent of ventricular geometry, heart rate, and blood pressure, and assesses both systolic and diastolic function", "It is more widely used", "It requires fewer measurements", "It correlates better with angiographic EF"], correctIndex: 0, rationale: "The Tei index does not rely on geometric assumptions about ventricular shape, making it valuable in RV assessment and ventricles with abnormal geometry. It incorporates both contraction and relaxation components, providing a global performance measure.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Tei Index" },
  { id: "cardecho-637", stem: "Which hemodynamic parameter is most useful for evaluating the severity of mitral stenosis during exercise?", options: ["Transmitral mean gradient and PA systolic pressure at peak exercise", "Resting LVEF", "Resting E/A ratio", "Aortic valve VTI"], correctIndex: 0, rationale: "Exercise increases heart rate and cardiac output, raising the transmitral gradient and PA pressure in significant MS. Exercise echo is indicated when symptoms are discordant with resting severity. A mean gradient >15 mmHg or PASP >60 mmHg at peak exercise suggests hemodynamically significant MS.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-638", stem: "Energy loss index (ELI) in aortic stenosis accounts for:", options: ["Pressure recovery in the ascending aorta, providing a more accurate assessment of AS severity in small aortas", "Flow acceleration at the valve tips", "Regurgitant volume through the valve", "Coronary perfusion pressure"], correctIndex: 0, rationale: "In small ascending aortas, significant pressure recovery occurs downstream of the stenosis, meaning the Doppler-derived gradient overestimates the net gradient. ELI = (EOA × Aa) / (Aa - EOA) / BSA, where Aa is the ascending aorta area. ELI <0.6 cm²/m² indicates severe AS.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-639", stem: "The concept of stroke volume index (SVI) is important in aortic stenosis grading because:", options: ["Low SVI (<35 mL/m²) identifies low-flow states where standard gradients may underestimate severity", "High SVI indicates severe AS", "SVI determines valve morphology", "SVI is used to measure regurgitant volume"], correctIndex: 0, rationale: "Low-flow AS (SVI <35 mL/m²) can occur with reduced LVEF (classical) or preserved LVEF (paradoxical). In both scenarios, the mean gradient may be <40 mmHg despite severe AS. Identifying low flow is crucial for appropriate grading and management.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-640", stem: "Paradoxical low-flow, low-gradient severe aortic stenosis with preserved LVEF is characterized by:", options: ["AVA <1.0 cm², mean gradient <40 mmHg, LVEF ≥50%, and SVI <35 mL/m² with a small hypertrophied LV cavity", "AVA >1.5 cm² with high gradient", "Normal AVA with high gradient", "Dilated LV with reduced EF"], correctIndex: 0, rationale: "Paradoxical low-flow AS occurs in patients with small, concentrically hypertrophied LVs that generate low stroke volume despite preserved EF. Restrictive physiology, female sex, hypertension, and elderly age are risk factors. CT calcium scoring helps confirm severity.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-641", stem: "During dobutamine stress echo for low-flow, low-gradient AS, true severe AS is confirmed when:", options: ["AVA remains ≤1.0 cm² despite increased flow, while the gradient increases to ≥40 mmHg", "AVA increases to >1.5 cm² with increased gradient", "There is no change in AVA or gradient", "Heart rate does not change"], correctIndex: 0, rationale: "With dobutamine, true severe AS shows a fixed small orifice: AVA stays ≤1.0 cm² while the gradient rises (≥40 mmHg). In pseudo-severe AS, the valve opens more with increased flow: AVA increases to >1.0 cm² and gradient rise is modest.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-642", stem: "The concept of projected valve area at normal flow rate is used in:", options: ["Low-flow AS to estimate what the valve area would be at a standardized flow rate of 250 mL/s", "Normal-flow AS to confirm severity", "Mitral stenosis assessment", "Tricuspid regurgitation quantification"], correctIndex: 0, rationale: "Projected AVA normalizes the measured AVA to a standard flow rate of 250 mL/s, accounting for flow-dependent changes in valve area. Projected AVA <1.0 cm² confirms true severe AS. This helps in cases where dobutamine stress results are ambiguous.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Valve Resistance" },
  { id: "cardecho-643", stem: "LV end-systolic elastance (Ees) is a load-independent measure of:", options: ["LV contractility, defined as the slope of the end-systolic pressure-volume relationship", "LV compliance", "Aortic valve area", "Right atrial pressure"], correctIndex: 0, rationale: "Ees represents intrinsic myocardial contractility independent of preload and afterload. It is the slope of the end-systolic pressure-volume relationship (ESPVR). Single-beat estimation methods using echocardiographic and blood pressure data have been validated.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-644", stem: "Arterial elastance (Ea) represents:", options: ["Effective arterial load or afterload, calculated as end-systolic pressure divided by stroke volume", "Arterial compliance only", "Venous return pressure", "Pulmonary artery pressure"], correctIndex: 0, rationale: "Ea = ESP / SV ≈ 0.9 × SBP / SV. It integrates arterial resistance, compliance, and impedance into a single parameter. Normal Ea is approximately 2.0 mmHg/mL. The Ea/Ees ratio (ventriculo-arterial coupling) optimally should be ~1.0.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-645", stem: "Ventriculo-arterial coupling (Ea/Ees ratio) assesses:", options: ["The interaction between ventricular contractility and arterial load for optimal mechanical efficiency", "Valve stenosis severity", "Diastolic function grade", "Shunt magnitude"], correctIndex: 0, rationale: "Optimal coupling occurs when Ea/Ees ≈ 0.7-1.0, maximizing cardiac efficiency. Ea/Ees >1.0 (uncoupling) occurs in heart failure when the ventricle cannot match the arterial load. It is a prognostic marker in HFrEF and aortic stenosis.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-646", stem: "Pulmonary artery capacitance can be estimated by:", options: ["Stroke volume divided by pulmonary artery pulse pressure (PASP - PADP)", "TR velocity × RVOT VTI", "IVC diameter × respiratory variation", "Mean PAP × cardiac output"], correctIndex: 0, rationale: "PA capacitance = SV / (PASP - PADP). It reflects the ability of the pulmonary vasculature to accommodate RV stroke volume. Reduced PA capacitance (<0.8 mL/mmHg) is an independent predictor of mortality in pulmonary hypertension.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-647", stem: "The RVOT fractional shortening can be used as a surrogate for:", options: ["Right ventricular systolic function when TAPSE and RV S' are suboptimal", "Left ventricular ejection fraction", "Mitral valve area", "Aortic root dimensions"], correctIndex: 0, rationale: "RVOT fractional shortening is measured in the PSAX view as (RVOTd - RVOTs) / RVOTd × 100%. Normal is >30%. It provides supplementary RV function assessment when standard measures (TAPSE, S', FAC) are limited by poor imaging windows.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-648", stem: "Tricuspid annular plane systolic excursion (TAPSE) measures RV function by:", options: ["M-mode measurement of the longitudinal displacement of the lateral tricuspid annulus during systole", "2D measurement of RV wall thickness", "Doppler measurement of tricuspid inflow", "Color Doppler assessment of TR severity"], correctIndex: 0, rationale: "TAPSE is a simple, reproducible measure of RV longitudinal function. Normal TAPSE ≥17 mm. TAPSE <17 mm indicates RV systolic dysfunction. It correlates with RV EF but reflects only basal free wall function and may be reduced after cardiac surgery.", difficulty: 1, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-649", stem: "RV S' (tricuspid annular systolic velocity by TDI) normal value is:", options: ["≥9.5 cm/s", "<5 cm/s", ">20 cm/s", ">30 cm/s"], correctIndex: 0, rationale: "RV S' is measured by PW TDI at the lateral tricuspid annulus. Normal S' ≥9.5 cm/s (some guidelines use ≥10 cm/s). S' <9.5 cm/s indicates RV systolic dysfunction. Like TAPSE, it reflects longitudinal RV function and may be affected by cardiac surgery.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-650", stem: "RV fractional area change (FAC) is measured by:", options: ["(RV end-diastolic area - RV end-systolic area) / RV end-diastolic area × 100%, from the apical 4-chamber view", "RVOT diameter change", "Tricuspid annular displacement", "IVC collapsibility index"], correctIndex: 0, rationale: "RV FAC is a 2D surrogate for RV EF. Normal FAC ≥35%. It accounts for both longitudinal and radial RV function, unlike TAPSE and S' which only assess longitudinal function. Accurate endocardial border tracing is essential.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-651", stem: "3D echocardiographic RV ejection fraction is the most accurate echocardiographic measure of RV systolic function because:", options: ["It captures the complex RV geometry without geometric assumptions, unlike 2D-derived surrogates", "It uses simpler calculations", "It requires fewer images", "It is less time-consuming"], correctIndex: 0, rationale: "The RV has a complex crescentic shape that makes 2D geometric models inaccurate. 3D echo directly measures RV volumes and EF without assumptions. Normal 3D RVEF is ≥45%. It correlates well with cardiac MRI RVEF, the reference standard.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-652", stem: "During the Valsalva maneuver, which hemodynamic change helps unmask pseudonormal filling?", options: ["Reduced preload decreases LAP, revealing an impaired relaxation pattern (E/A <0.8)", "Increased afterload raises the E/A ratio", "Heart rate increases dramatically", "Blood pressure rises significantly"], correctIndex: 0, rationale: "Valsalva reduces venous return (preload), lowering LAP. In pseudonormal filling, the reduced LAP unmasks the underlying impaired relaxation: E velocity decreases, A velocity increases, and E/A reverses to <0.8. A decrease in E/A ratio ≥0.5 is considered significant.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-653", stem: "The L-wave on mitral inflow Doppler is seen in which condition?", options: ["Elevated LV filling pressures with mid-diastolic flow due to continued LA-to-LV pressure gradient", "Normal diastolic function", "Aortic stenosis", "Mitral stenosis always"], correctIndex: 0, rationale: "The L-wave is a mid-diastolic flow velocity between E and A waves, indicating a persistent LA-to-LV gradient. It is seen with elevated LAP, prolonged LV relaxation, or slow heart rates. Its presence suggests significant diastolic dysfunction.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-654", stem: "Color M-mode propagation velocity (Vp) of mitral inflow is used to:", options: ["Assess LV relaxation; Vp <45 cm/s suggests impaired relaxation", "Measure aortic valve gradient", "Assess RV function", "Quantify mitral regurgitation"], correctIndex: 0, rationale: "Vp measures the speed of early filling propagation from the mitral annulus to the apex. Normal Vp ≥45 cm/s (some use >50 cm/s). E/Vp ratio >2.5 estimates elevated PCWP. Vp is relatively preload-independent but has limited accuracy in normal EF.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-655", stem: "The left atrial volume index (LAVI) is elevated (>34 mL/m²) in which setting?", options: ["Chronic elevation of LV filling pressure, serving as a surrogate for long-term diastolic dysfunction", "Acute dehydration", "Normal diastolic function in young athletes", "Isolated systolic hypertension without diastolic dysfunction"], correctIndex: 0, rationale: "LA volume reflects the cumulative effect of elevated filling pressures over time (the HbA1c of diastolic function). LAVI >34 mL/m² is abnormal and is a criterion for diastolic dysfunction. LAVI is also prognostic for AF, stroke, and heart failure.", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-656", stem: "The 2016 ASE/EACVI algorithm for grading diastolic function uses which four key variables?", options: ["Mitral annular e' velocity, E/e' ratio, LAVI, and TR velocity", "E/A ratio, DT, IVRT, and Vp", "LVEF, LV mass, E/A ratio, and heart rate", "TAPSE, S', FAC, and RVSP"], correctIndex: 0, rationale: "The 2016 guidelines use: septal e' <7 or lateral e' <10, average E/e' >14, LAVI >34 mL/m², and TR velocity >2.8 m/s. ≥3 of 4 abnormal = elevated filling pressures. This simplified algorithm replaced the more complex multi-parameter approach.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-657", stem: "In a patient with normal LVEF and indeterminate diastolic function by the 2016 algorithm, which additional parameter may help?", options: ["Pulmonary vein S/D ratio, mitral E/A ratio during Valsalva, or exercise diastolic stress testing", "Aortic valve VTI", "RV wall thickness", "Coronary sinus Doppler"], correctIndex: 0, rationale: "When 2 of 4 criteria are positive (indeterminate), ancillary parameters such as PV S/D ratio <1, E/A decrease ≥0.5 with Valsalva, or exercise E/e' >14 may help. If still indeterminate, clinical context and longitudinal follow-up guide management.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-658", stem: "The LV untwisting rate, measured by speckle tracking, reflects:", options: ["LV diastolic function, specifically the early active relaxation phase of diastole", "LV systolic contractility", "RV function", "Valve stenosis severity"], correctIndex: 0, rationale: "LV untwisting is an active energy-dependent process that occurs during isovolumic relaxation and early filling, generating the suction force for early LV filling. Reduced untwisting rate is an early marker of diastolic dysfunction.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-659", stem: "Myocardial work index, derived from strain and blood pressure, offers which advantage over GLS alone?", options: ["It accounts for afterload, providing a more accurate assessment of intrinsic myocardial contractility", "It is simpler to calculate", "It does not require speckle tracking", "It only measures diastolic function"], correctIndex: 0, rationale: "GLS is affected by loading conditions. Myocardial work (pressure-strain loops) integrates strain with LV pressure, estimated from brachial BP and valve timing. It separates constructive work from wasted work, improving detection of contractile dysfunction.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-660", stem: "Wasted myocardial work occurs when:", options: ["Myocardial segments shorten during diastole or lengthen during systole, not contributing to ventricular ejection", "All segments contract synchronously during systole", "The heart rate is normal", "Valve function is normal"], correctIndex: 0, rationale: "Wasted work reflects dyssynergy: segments that stretch during systole (absorbing energy) or shorten inappropriately during diastole. High wasted work relative to constructive work (low myocardial work efficiency) is seen in LBBB and ischemia.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-661", stem: "In evaluating intracardiac shunts, the oximetric method in the cath lab compares:", options: ["Oxygen saturation at different levels of the right heart to identify a step-up indicating shunt location", "Pressure gradients across valves", "Contrast injection timing", "ECG changes during catheter advancement"], correctIndex: 0, rationale: "An O₂ saturation step-up >7% at the atrial level (ASD), >5% at the ventricular level (VSD), or >5% at the great vessel level (PDA) indicates a significant left-to-right shunt. The magnitude of step-up correlates with Qp/Qs.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-662", stem: "The net shunt flow through an ASD can be directly measured by:", options: ["Color Doppler flow area times VTI at the defect, though this is technically challenging due to defect geometry", "Agitated saline contrast appearance timing", "IVC diameter measurement", "LA volume measurement alone"], correctIndex: 0, rationale: "Direct Doppler measurement at the ASD is possible but limited by the irregular defect shape and flow angle. The Qp/Qs method (RVOT SV / LVOT SV) is more reliable. 3D echo with color Doppler can improve direct ASD flow quantification.", difficulty: 4, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-663", stem: "In an Eisenmenger VSD, the Doppler findings include:", options: ["Bidirectional or predominantly right-to-left shunting with low-velocity flow across the VSD", "High-velocity left-to-right jet across the VSD", "No flow across the defect", "Systolic flow reversal in the aorta"], correctIndex: 0, rationale: "Eisenmenger physiology occurs when pulmonary hypertension causes reversal of the shunt direction (right-to-left). The low-velocity bidirectional flow reflects near-equalization of LV and RV pressures. Cyanosis results from right-to-left shunting.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
  { id: "cardecho-664", stem: "The time constant of LV relaxation (tau, τ) is:", options: ["An invasive gold-standard measure of active LV relaxation, calculated from the isovolumic pressure decline", "A Doppler-derived parameter measured routinely", "The same as IVRT", "A measure of LV contractility"], correctIndex: 0, rationale: "Tau is measured invasively as the time constant of isovolumic pressure decay. Normal tau is ~30-50 ms. It reflects active (energy-dependent) relaxation. Prolonged tau indicates diastolic dysfunction. Echo parameters like e' and IVRT serve as non-invasive surrogates.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-665", stem: "LV global constructive work (GCW) is defined as:", options: ["Work performed by segments shortening during systole plus work performed by segments lengthening during isovolumic relaxation", "Total work minus wasted work", "Only the systolic shortening component", "Only the diastolic relaxation component"], correctIndex: 0, rationale: "GCW includes myocardial shortening during systole (when LV pressure is positive) and lengthening during isovolumic relaxation (assisting relaxation). Normal GCW is approximately 1800-2200 mmHg%. It is reduced in cardiomyopathies and ischemia.", difficulty: 5, category: "Advanced Hemodynamics", topic: "Cardiac Output Methods" },
  { id: "cardecho-666", stem: "The ratio of early transmitral flow velocity to flow propagation velocity (E/Vp) >2.5 suggests:", options: ["Elevated LV filling pressure (PCWP >15 mmHg)", "Normal filling pressure", "Pulmonic stenosis", "Aortic regurgitation"], correctIndex: 0, rationale: "E/Vp combines the filling velocity (E) with the propagation velocity (Vp, reflecting relaxation). When Vp is low (slow relaxation) and E is high (elevated LAP driving flow), E/Vp rises. E/Vp >2.5 estimates PCWP >15 mmHg.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-667", stem: "The modified Bernoulli equation used in echocardiography simplifies the full Bernoulli equation by:", options: ["Assuming the proximal velocity is negligible (<1 m/s), eliminating the viscous friction and flow acceleration terms", "Adding atmospheric pressure to the calculation", "Including gravitational effects", "Measuring temperature effects on blood flow"], correctIndex: 0, rationale: "Full Bernoulli: ΔP = ½ρ(V₂² - V₁²) + viscous losses + flow acceleration. Simplified: ΔP = 4V². This assumes proximal V₁ is negligible, viscous friction is minimal (not true in long tunnels), and flow acceleration is small (not true in acute obstruction).", difficulty: 2, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-668", stem: "When the proximal velocity (V1) is >1.5 m/s, the modified Bernoulli equation should be expanded to:", options: ["ΔP = 4(V₂² - V₁²) to avoid overestimation of the pressure gradient", "ΔP = 4V₂² + 4V₁²", "ΔP = 4V₂² only", "ΔP = V₂ - V₁"], correctIndex: 0, rationale: "When V₁ >1.5 m/s (e.g., in series stenoses, subaortic membrane + AS, or significant LVOT obstruction), ignoring V₁ significantly overestimates the gradient. The expanded equation ΔP = 4(V₂² - V₁²) corrects for this.", difficulty: 3, category: "Advanced Hemodynamics", topic: "Intracardiac Pressures" },
  { id: "cardecho-669", stem: "The concept of flow convergence is based on which physics principle?", options: ["Conservation of mass: as flow approaches a restrictive orifice, velocity increases and flow organizes into concentric isovelocity hemispheres", "Bernoulli principle only", "Doppler effect only", "Reflection of ultrasound waves"], correctIndex: 0, rationale: "Flow convergence (PISA) is based on conservation of mass: flow rate (Q = Area × Velocity) is constant. As blood approaches a small orifice, the area decreases so velocity must increase. At each radius from the orifice, Q = 2πr² × Vr (hemisphere).", difficulty: 3, category: "Advanced Hemodynamics", topic: "Shunt Calculations" },
];
